const raw = $.input.jsonData || '{}';
let data;
try { data = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch(e) { data = { rawText: raw }; }

const isArray = Array.isArray(data);
const recordCount = isArray ? data.length : 1;
const fields = isArray && data.length > 0 ? Object.keys(data[0]) : Object.keys(data);
const preview = JSON.stringify(isArray ? data.slice(0, 3) : data, null, 2).slice(0, 3000);

return { data: JSON.stringify(data).slice(0, 30000), isArray, recordCount, fields, preview };

const d = $.steps.parseInput.output;
const title = $.input.reportTitle || 'Data Report';
const reportType = $.input.reportType || 'summary';

let prompt = 'You are a data analyst. Transform the following JSON data into a well-formatted ' + reportType + ' report.\n\n';
prompt += 'REPORT TITLE: ' + title + '\n';
prompt += 'REPORT TYPE: ' + reportType + '\n';
prompt += 'DATA INFO: ' + d.recordCount + ' records, Fields: ' + d.fields.join(', ') + '\n\n';
prompt += 'DATA:\n' + d.data + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For summary: high-level overview, key metrics, trends\n';
prompt += '- For detailed: break down each record/group with analysis\n';
prompt += '- For executive: concise highlights, actionable recommendations\n';
prompt += '- For comparison: identify similarities, differences, rankings\n';
prompt += '- Calculate totals, averages, min/max where applicable\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "report title",\n';
prompt += '  "highlight": "one-line key takeaway",\n';
prompt += '  "metrics": [{ "label": "Total Records", "value": "100" }],\n';
prompt += '  "sections": [{ "heading": "Section Title", "content": "formatted section content" }],\n';
prompt += '  "recommendations": ["recommendation 1", "recommendation 2"],\n';
prompt += '  "dataQualityNotes": "any issues with the input data"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.reportTitle || 'Data Report', highlight: '', metrics: [], sections: [{ heading: 'Report', content: raw.slice(0, 2900) }], recommendations: [], dataQualityNotes: '' }; }

const ai = $.steps.parseAI.output;
const d = $.steps.parseInput.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: (ai.title || 'Data Report').slice(0, 150), emoji: true } });

if (ai.highlight) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':bulb: *Key Takeaway:* ' + ai.highlight } });
}

if (ai.metrics && ai.metrics.length > 0) {
  let metricsText = '*Key Metrics:*\n';
  ai.metrics.forEach(m => { metricsText += '*' + m.label + ':* ' + m.value + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: metricsText.slice(0, 2900) } });
}
blocks.push({ type: 'divider' });

(ai.sections || []).forEach(section => {
  if (section.heading) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + section.heading + '*' } });
  }
  if (section.content) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: section.content.slice(0, 2900) } });
  }
  blocks.push({ type: 'divider' });
});

if (ai.recommendations && ai.recommendations.length > 0) {
  let recText = ':white_check_mark: *Recommendations:*\n';
  ai.recommendations.forEach((r, i) => { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 2900) } });
}

if (ai.dataQualityNotes) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':mag: Data quality: ' + ai.dataQualityNotes }] });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Records: ' + d.recordCount + ' | Fields: ' + d.fields.join(', ') + ' | Generated with Claude AI | One CLI' }] });

const fallback = (ai.title || 'Data Report') + ': ' + d.recordCount + ' records - ' + (ai.highlight || '').slice(0, 100);
return { blocks, fallback };
